var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐야……?","JPN":"なに……？","ENG":"What…?","TWN":"是怎樣……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석……. 총 한 발에 갑자기 멈췄잖아?","JPN":"あいつ……銃一発で動きが止まった？","ENG":"That thing… All it took was a bullet to stop it?","TWN":"那傢伙……突然因為一顆子彈就停下來？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"컥…… 커헉……","JPN":"ぐあ……ガハッ……","ENG":"Ack… Hngh…","TWN":"咳……咳咳……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시…… 예상대로군요.","JPN":"やはり……予想どおりですね。","ENG":"Just as I expected…","TWN":"果然……跟我想的一樣。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 의지에 따라 강해진다면, 제 의지에 따라 파괴될 수도 있다는 뜻이겠죠.","JPN":"僕の意志によって強くなるなら、僕の意志によって破壊されることもあるってことでしょう。","ENG":"If it can grow strong from my resolve, that also means I could destroy it with my resolve.","TWN":"如果他能夠照著我的意志變強，那我也就可以照著我的意志毀掉他。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런 가벼운 총탄 하나에 핏물로 변해 버리다니…….","JPN":"こんな普通の弾一発で血に変わってしまうなんて……","ENG":"To think it only took a bullet to turn that thing to a puddle of blood…","TWN":"竟然區區一顆子彈就把他變成一攤血……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비장의 무기로 쓰시기엔 약점이 너무 명확한 것 같네요.","JPN":"切り札として使うには、弱点があまりにも明確なようですね。","ENG":"It's got a gaping flaw to use as your ultimate weapon, don't you think?","TWN":"說他是你的祕密武器未免也太弱？"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다음엔 좀 더 신뢰성을 갖춘 괴물을 만드시는 편이 좋겠어요.","JPN":"次はもう少し信頼性の高い化け物を作ったほうがいいんじゃないですか？","ENG":"You should try to design a more reliable monster next time.","TWN":"建議你下次可以做一些比較可靠的怪物。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 친절하게 가르쳐 주신 건 고마웠어요.","JPN":"ああ、親切に教えてくださったのは助かりました。","ENG":"Thanks for the tip though.","TWN":"喔，還有，謝謝你剛剛親切的說明。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……이해할 수가 없군요.","JPN":"……理解できません。","ENG":"…I don't understand.","TWN":"我不懂……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용인을 파괴해버리면 당신도, 당신의 부모도 구원받을 길이 없습니다.","JPN":"龍人を破壊してしまうと、あなたも、あなたの両親も救われる手段が無くなるのですよ？","ENG":"If you destroy the Dragonoid, neither you nor your parents can be redeemed.","TWN":"毀掉龍人，不只是你，你的父母也無法得到救贖。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런데 어째서…….","JPN":"なのにどうして……","ENG":"So why…","TWN":"為什麼你……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……간단해요.","JPN":"……簡単です。","ENG":"…It's simple.","TWN":"……答案很簡單。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 귀가 밝은 편이거든요.","JPN":"僕は地獄耳ですので。","ENG":"I've got pretty good hearing.","TWN":"因為我的耳朵很敏銳。"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7090010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배? 그 총은 뭐야?","JPN":"先輩？　その銃はなに？","ENG":"Shiyoon? What's with the gun?","TWN":"前輩？怎麼會有那把槍？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"방금 선배가 이 녀석을 쓰러트린 거야?","JPN":"今先輩がこいつを倒したの？","ENG":"Did you shoot that thing just now?","TWN":"剛剛是前輩打中那傢伙嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"역시 대단해! 칼만 잘 쓰는 게 아니었나 보네!","JPN":"やっぱりすごい！　剣以外にも才能があったんだね！","ENG":"That was impressive! I guess the sword isn't the only thing you're good with!","TWN":"果然厲害！我還以為你只會舞刀弄劍的！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 제가 좀 대단하긴 하죠.","JPN":"ハハ、僕にもちょっとすごいところはあるでしょう？","ENG":"Haha, I guess I'm pretty impressive like that…","TWN":"哈哈～我是滿厲害的沒錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만…… 그것도 여기까지네요.","JPN":"でも……それもここまでです。","ENG":"But… I think that's all I've got for now.","TWN":"只是……到此為止了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아쉽지만 더 이상은 도와드릴 수가 없을 것 같아요.","JPN":"残念ながら、これ以上はお役に立てそうにありません。","ENG":"I'm afraid I can't help you anymore.","TWN":"真可惜，我只能幫你到這裡而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐? 갑자기 무슨 소리야?","JPN":"え？　急にどうしたの？","ENG":"Huh? What are you talking about?","TWN":"嗯？為什麼突然這麼說？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이라면 저 없이도 잘 해낼 수 있을 거예요.","JPN":"ミナさんなら僕がいなくてもうまくやれるでしょう。","ENG":"I'm sure you'll be great, even without me.","TWN":"我相信米娜就算沒有我也可以搞定的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 스승님한테 그동안 고마웠다고 전해 주세요.","JPN":"だから……師匠にはこれまでのことに感謝しているとお伝えください。","ENG":"So please… tell Master that I said thank you for everything.","TWN":"還有……幫我跟師父說，謝謝他這段時間的照顧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부모님께서도, 그렇게 생각하실 거라고.","JPN":"僕の両親もそう思っているはずだと。","ENG":"Tell her that my parents are probably grateful as well.","TWN":"相信我父母也是這麼想的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대, 대체 왜 그래? 꼭 헤어질 사람처럼?","JPN":"い、いったいどうしたの？　まるでいなくなりそうな言い方じゃない。","ENG":"W-why are you being like this? You're acting as if you'll never see me again!","TWN":"你跟我說這些幹嘛？一副好像你要離開的樣子。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"실망스럽군요. 이방인이여.","JPN":"残念です、異邦人よ。","ENG":"That is most disappointing, outsider.","TWN":"外邦人，我對你太失望了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이라면 제 말을 이해할 수 있을 줄 알았건만.","JPN":"あなたなら私の話を理解してくれると思ったのに。","ENG":"I thought you of all people would understand me.","TWN":"我還以為你可以明白我說的話。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신?! 알렌 선생님의 집에서 봤던 그 사람이잖아!","JPN":"あなたは！？　アレン先生の家で会った人じゃない！","ENG":"You?! You're that lady from Mr. Birmingham's place!","TWN":"你不是？！那時候在艾倫老師家看到的那個人！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"갑자기 어디서 나타난 거야? 선배한테서 떨어져!","JPN":"いきなりどこから現れたの？　先輩から離れて！","ENG":"Where did you pop out of? Get away from Shiyoon!","TWN":"你是從哪裡蹦出的？給我離前輩遠一點！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 자신을 이해해 주는 사람을 만나기란 어려운 법이죠.","JPN":"ハハ、自分のことを理解してくれる人に出会うのは中々難しいものです。","ENG":"Haha, it's rare to find someone who can completely understand you.","TWN":"哈哈，要遇到懂你的人本來就不是件易事，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"세상이 원래 그렇잖아요?","JPN":"世の中そんなものですよ。","ENG":"That's just the way the world works, isn't it?","TWN":"人生不就是這樣嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……하긴, 그렇군요.","JPN":"……まあ、そうですね。","ENG":"…Well, I suppose you're right.","TWN":"……也是，你說的沒錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"인간이 어리석은 선택을 하는 것도 원래 그런 법이죠.","JPN":"人間が愚かな選択をするのも世の常。","ENG":"Likewise, people make foolish choices.","TWN":"而人類也總是做出愚蠢的決定。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 정말, 구도자의 후손이 맞군요.","JPN":"あなたは本当に、求道者の子孫ですね。","ENG":"You really must have descended from the Seeker.","TWN":"你果真是求道者的後裔沒錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그럼…… 고통 속에서 편히 쉬시길.","JPN":"それでは……苦痛の中で安らかに。","ENG":"Very well… May you rest in peace and agony.","TWN":"那麼……你就在痛苦中安息吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배! 도망쳐! 내가…… 내가 구해 줄게!","JPN":"先輩！　逃げて！　私が……私が助ける！","ENG":"Shiyoon! Run away! I'll… I'll save you!","TWN":"前輩！你快逃！我……我會救你出去！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배!!","JPN":"先輩！！","ENG":"Shiyoon!!","TWN":"前輩！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배! 정신차려! 선배!","JPN":"先輩！　しっかりして、先輩！！","ENG":"Shiyoon! Wake up! Shiyoon!","TWN":"前輩！你醒一醒！前輩！"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"장난치는 거지? 선배가 죽을 리가 없잖아?","JPN":"冗談だよね？　先輩が死ぬはずない！","ENG":"You're just messing with me, right? There's no way you'd die so easily!","TWN":"你是在跟我開玩笑嗎？你怎麼可能會死！"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"일어나! 어서 일어나라고, 주시윤!!","JPN":"起きて！　はやく起きてよ！　アキヤマ・シリュウ！！","ENG":"Wake up! Wake up, Joo Shiyoon!!","TWN":"你起來！你快點起來！周時雲！！"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그는 죽었습니다.","JPN":"彼は死にました。","ENG":"He is dead.","TWN":"他已經死了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 아니었으면 여기서 죽을 필요는 없었습니다.","JPN":"あなたでなければここで死ぬ必要はありませんでした。","ENG":"He would not have had to perish here if it wasn't for you.","TWN":"要不是因為你，他也不用死在這裡，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그를 죽인 건 당신이 한 것과 마찬가지죠.","JPN":"彼を殺したのはあなたも同然です。","ENG":"You might as well have killed him yourself.","TWN":"他就等於是你殺死的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"너……!","JPN":"あんた……！","ENG":"You…!","TWN":"你……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"동료를 애도하는 모습이 이렇게나 보기 역겨울 수도 있군요.","JPN":"仲間の死を悼む姿で、ここまで気分が悪くなることもあるのですね｡","ENG":"I did not realize mourning a colleague could be so nauseating to watch.","TWN":"原來哀悼同事的樣子可以這麼令人作噁。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 저지른 그 모든 일에도 불구하고 겨우 이 정도로 슬퍼하는 건가요, 늑대여?","JPN":"あなたが今まで犯したことに比べたら些細なことなのに、たったこの程度で悲しむのですか、狼よ。","ENG":"After all the atrocities you've committed, this is all it takes to break your heart, ye treacherous Wolf?","TWN":"也不想想你的所作所為，結果你的傷痛不過如此嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아, 어차피 기억하지 못한다고 하겠죠. 그것 참 편리한 변명이군요.","JPN":"ああ、どうせ覚えていないと言うのでしょう。実に便利な言い訳ですね。","ENG":"Oh, right. You'll just say that you can't remember a thing. How convenient.","TWN":"哦～反正你會說你不記得對吧？這真是個好藉口呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"닥쳐…….","JPN":"黙れ……","ENG":"Shut up…","TWN":"住口……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"모든 것을 잊어 버린 당신을 위해 제가 친절히 가르쳐 드리죠.","JPN":"すべてを忘れたあなたのために、私が親切に教えてさしあげます。","ENG":"Let me kindly talk you through what will happen now, since you have forgotten everything.","TWN":"既然你什麼都不記得，那我就好心地告訴你吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신 때문에 죽은 그 소년은 용혈의 망령으로 전락할 것입니다.","JPN":"あなたのせいで死んだあの少年は龍血の亡霊へと堕ちてしまうでしょう。","ENG":"Because of you, in death that lad will become a lost soul of Dragon Blood.","TWN":"這個被你害死的年輕人會墮落到龍血的亡靈，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 곳에서 역시 망령이 된 그의 부모들과 함께 영원한 고통을…….","JPN":"そこで同じように亡霊となった彼の両親と共に、終わらない永年の苦しみを……","ENG":"Like his parents, his soul will forever be tormented…","TWN":"他會在那裡和他的父母一起在永遠的痛苦中……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"닥치라고 했어!","JPN":"黙れと言ったでしょ！","ENG":"I said, shut up!","TWN":"我叫你住口！！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG_02"},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"네가 누구든, 얼마나 강하든 상관없어.","JPN":"あんたが誰だろうが、どれだけ強かろうが構わない。","ENG":"I don't care who you are or how powerful you may be.","TWN":"我不管你是誰，不管你有多強，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 가진 힘, 그게 뭐든 전부를 걸어서라도……!","JPN":"私が持っている力、それが何であれすべてを賭けて……！","ENG":"I'll use every bit of my power and everything it takes…","TWN":"我都會用盡我所有的力量……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"반드시 쓰러트려 주겠어!","JPN":"必ず倒してやる！","ENG":"And take you down!","TWN":"打！倒！你！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……그래요.","JPN":"……いいでしょう。","ENG":"…Very well.","TWN":"……很好，"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이제서야 저도 조금은 만족감이 느껴지는군요.","JPN":"ようやく私も少しは満足感を感じられますね。","ENG":"I can finally draw some satisfaction out of this entire ordeal.","TWN":"這樣才對嘛～否則我原本還有點失落呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"더 증오하고, 더 분노하세요.","JPN":"より憎悪し、より憤怒しなさい。","ENG":"Let your hate and anger rage on.","TWN":"你再更生氣、更恨我一點！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 입는 상처야말로, 제겐 가장 큰 쾌락이니까요.","JPN":"あなたの苦しみこそ、私にとって最上級の快楽ですから。","ENG":"For nothing brings me more pleasure than your suffering.","TWN":"因為你越是傷心難過我就越開心！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……저주받은 늑대여.","JPN":"……呪われた狼よ。","ENG":"…Ye Cursed Wolf.","TWN":"……受到詛咒的狼。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};